import java.util.ArrayList;
import java.util.List;

class Solution {
    public List<List<Integer>> subsets(int[] nums) {
        List<List<Integer>> result = new ArrayList<>();
        List<Integer> currentSubset = new ArrayList<>();
        // Start the backtracking process from index 0
        backtrack(nums, 0, currentSubset, result);
        return result;
    }

    private void backtrack(int[] nums, int start, List<Integer> currentSubset, List<List<Integer>> result) {
        // Add the current subset to the result list. 
        // It's crucial to add a *copy* of currentSubset,
        // because currentSubset will be modified later.
        result.add(new ArrayList<>(currentSubset));

        // Explore further elements to build larger subsets
        for (int i = start; i < nums.length; i++) {
            // Include nums[i] in the current subset
            currentSubset.add(nums[i]);

            // Recurse with the next index (i + 1)
            // This ensures elements are not reused in a single subset
            // and maintains the order of chosen elements.
            backtrack(nums, i + 1, currentSubset, result);

            // Backtrack: Remove nums[i] to explore subsets 
            // that do not include nums[i] (or include it with other combinations)
            currentSubset.remove(currentSubset.size() - 1);
        }
    }
}
